--
-- Name: hybrid_search_rank(double precision, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.hybrid_search_rank(fts_rank double precision, semantic_similarity double precision, fts_weight double precision DEFAULT 0.3, semantic_weight double precision DEFAULT 0.7) RETURNS double precision
    LANGUAGE plpgsql IMMUTABLE
    AS $$
        BEGIN
            -- Reciprocal Rank Fusion style combination
            -- Normalize both scores to 0-1 range and combine with weights
            RETURN (fts_weight * LEAST(fts_rank, 1.0)) +
                   (semantic_weight * COALESCE(semantic_similarity, 0));
        END;
        $$;


