--
-- Name: rag_hybrid_search(public.vector, text, double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rag_hybrid_search(query_embedding public.vector, query_text text, semantic_weight double precision DEFAULT 0.7, keyword_weight double precision DEFAULT 0.3, match_count integer DEFAULT 20) RETURNS TABLE(chunk_id uuid, document_id uuid, chunk_text text, combined_score double precision, semantic_score double precision, keyword_score double precision)
    LANGUAGE plpgsql
    AS $$
        BEGIN
            RETURN QUERY
            WITH semantic_results AS (
                SELECT
                    c.id,
                    c.document_id,
                    c.chunk_text,
                    1 - (c.embedding <=> query_embedding) AS score
                FROM rag_document_chunks c
                ORDER BY c.embedding <=> query_embedding
                LIMIT match_count * 2
            ),
            keyword_results AS (
                SELECT
                    c.id,
                    c.document_id,
                    c.chunk_text,
                    similarity(c.chunk_text, query_text) AS score
                FROM rag_document_chunks c
                WHERE c.chunk_text % query_text
                ORDER BY similarity(c.chunk_text, query_text) DESC
                LIMIT match_count * 2
            ),
            combined AS (
                SELECT
                    COALESCE(s.id, k.id) AS id,
                    COALESCE(s.document_id, k.document_id) AS document_id,
                    COALESCE(s.chunk_text, k.chunk_text) AS chunk_text,
                    COALESCE(s.score, 0) AS sem_score,
                    COALESCE(k.score, 0) AS kw_score
                FROM semantic_results s
                FULL OUTER JOIN keyword_results k ON s.id = k.id
            )
            SELECT
                combined.id AS chunk_id,
                combined.document_id,
                combined.chunk_text,
                (combined.sem_score * semantic_weight + combined.kw_score * keyword_weight) AS combined_score,
                combined.sem_score AS semantic_score,
                combined.kw_score AS keyword_score
            FROM combined
            ORDER BY combined_score DESC
            LIMIT match_count;
        END;
        $$;


--
-- Name: rag_semantic_search(public.vector, double precision, integer, uuid[], character varying[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rag_semantic_search(query_embedding public.vector, match_threshold double precision DEFAULT 0.7, match_count integer DEFAULT 20, filter_document_ids uuid[] DEFAULT NULL::uuid[], filter_section_types character varying[] DEFAULT NULL::character varying[]) RETURNS TABLE(chunk_id uuid, document_id uuid, chunk_text text, chunk_index integer, page_number integer, section_type character varying, similarity double precision)
    LANGUAGE plpgsql
    AS $$
        BEGIN
            RETURN QUERY
            SELECT
                c.id AS chunk_id,
                c.document_id,
                c.chunk_text,
                c.chunk_index,
                c.page_number,
                c.section_type,
                1 - (c.embedding <=> query_embedding) AS similarity
            FROM rag_document_chunks c
            WHERE
                -- Similarity Threshold
                1 - (c.embedding <=> query_embedding) > match_threshold
                -- Optional Document Filter
                AND (filter_document_ids IS NULL OR c.document_id = ANY(filter_document_ids))
                -- Optional Section Type Filter
                AND (filter_section_types IS NULL OR c.section_type = ANY(filter_section_types))
            ORDER BY c.embedding <=> query_embedding
            LIMIT match_count;
        END;
        $$;


--
-- Name: rag_update_updated_at_column(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rag_update_updated_at_column() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
        BEGIN
            NEW.updated_at = NOW();
            RETURN NEW;
        END;
        $$;


--
-- Name: refresh_search_analytics_daily(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_search_analytics_daily() RETURNS void
    LANGUAGE plpgsql
    AS $$
        BEGIN
            REFRESH MATERIALIZED VIEW CONCURRENTLY search_analytics_daily;
        END;
        $$;


--
-- Name: set_document_access_log_sequence(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_document_access_log_sequence() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
        BEGIN
            NEW.sequence_number := nextval('document_access_log_seq');
            RETURN NEW;
        END;
        $$;


--
-- Name: tunes_update_updated_at_column(); Type: FUNCTION; Schema: public; Owner: -
