--
-- Name: alerts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.alerts (
    id uuid NOT NULL,
    alert_code character varying(50) NOT NULL,
    title character varying(255) NOT NULL,
    message text NOT NULL,
    category character varying(30) DEFAULT 'system'::character varying NOT NULL,
    severity character varying(20) DEFAULT 'medium'::character varying NOT NULL,
    status character varying(20) DEFAULT 'new'::character varying NOT NULL,
    source_type character varying(50),
    source_id character varying(100),
    document_id uuid,
    entity_id uuid,
    company_id uuid NOT NULL,
    assigned_to_id uuid,
    alert_metadata jsonb DEFAULT '{}'::jsonb,
    context jsonb DEFAULT '{}'::jsonb,
    available_actions jsonb DEFAULT '[]'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    acknowledged_at timestamp with time zone,
    acknowledged_by_id uuid,
    resolved_at timestamp with time zone,
    resolved_by_id uuid,
    resolution_note text,
    resolution_action character varying(100),
    auto_dismiss_at timestamp with time zone,
    is_recurring boolean DEFAULT false,
    recurrence_key character varying(255),
    email_sent boolean DEFAULT false,
    email_sent_at timestamp with time zone,
    escalation_level integer DEFAULT 0,
    escalated_at timestamp with time zone,
    escalated_to_id uuid,
    CONSTRAINT ck_alerts_category CHECK (((category)::text = ANY ((ARRAY['fraud'::character varying, 'risk'::character varying, 'compliance'::character varying, 'deadline'::character varying, 'system'::character varying, 'security'::character varying, 'quality'::character varying, 'workflow'::character varying])::text[]))),
    CONSTRAINT ck_alerts_severity CHECK (((severity)::text = ANY ((ARRAY['info'::character varying, 'low'::character varying, 'medium'::character varying, 'high'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT ck_alerts_status CHECK (((status)::text = ANY ((ARRAY['new'::character varying, 'acknowledged'::character varying, 'in_progress'::character varying, 'resolved'::character varying, 'dismissed'::character varying, 'escalated'::character varying])::text[])))
);


--
-- Name: anomalies; Type: TABLE; Schema: public; Owner: -
