    source_id uuid NOT NULL,
    related_ids jsonb DEFAULT '[]'::jsonb,
    score double precision DEFAULT 0.0,
    details jsonb DEFAULT '{}'::jsonb,
    status character varying(20) DEFAULT 'open'::character varying NOT NULL,
    resolved_at timestamp with time zone,
    resolved_by_id uuid,
    resolution_note text,
    company_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_anomalies_score_range CHECK (((score >= (0)::double precision) AND (score <= (1)::double precision))),
    CONSTRAINT ck_anomalies_severity CHECK (((severity)::text = ANY ((ARRAY['info'::character varying, 'warning'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT ck_anomalies_status CHECK (((status)::text = ANY ((ARRAY['open'::character varying, 'investigating'::character varying, 'resolved'::character varying, 'false_positive'::character varying])::text[])))
);


