--
-- Name: autonomy_settings; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.autonomy_settings (
    id uuid NOT NULL,
    company_id uuid NOT NULL,
    autonomy_level character varying(30) DEFAULT 'conservative'::character varying NOT NULL,
    category_overrides jsonb,
    low_confidence_threshold double precision DEFAULT '0.8'::double precision NOT NULL,
    high_confidence_threshold double precision DEFAULT '0.95'::double precision NOT NULL,
    default_timeout_hours integer DEFAULT 24 NOT NULL,
    auto_approve_on_timeout boolean DEFAULT false NOT NULL,
    notify_on_auto_execute boolean DEFAULT true NOT NULL,
    notify_channels jsonb,
    require_dual_approval boolean DEFAULT false NOT NULL,
    dual_approval_categories jsonb,
    daily_auto_execute_limit integer,
    max_single_action_value double precision,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    updated_by_id uuid,
    CONSTRAINT ck_autonomy_level CHECK (((autonomy_level)::text = ANY ((ARRAY['conservative'::character varying, 'smart_hybrid'::character varying, 'progressive'::character varying, 'zero_touch'::character varying])::text[]))),
    CONSTRAINT ck_high_threshold_range CHECK (((high_confidence_threshold >= (0.0)::double precision) AND (high_confidence_threshold <= (1.0)::double precision))),
    CONSTRAINT ck_low_threshold_range CHECK (((low_confidence_threshold >= (0.0)::double precision) AND (low_confidence_threshold <= (1.0)::double precision))),
    CONSTRAINT ck_threshold_order CHECK ((low_confidence_threshold < high_confidence_threshold))
);


--
-- Name: TABLE autonomy_settings; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.autonomy_settings IS 'Autonomie-Einstellungen pro Company';


