--
-- Name: contracts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.contracts (
    id uuid NOT NULL,
    document_id uuid,
    contract_number character varying(100),
    title character varying(500) NOT NULL,
    description text,
    contract_type character varying(50) DEFAULT 'other'::character varying NOT NULL,
    status character varying(30) DEFAULT 'draft'::character varying NOT NULL,
    parties jsonb DEFAULT '[]'::jsonb,
    our_role character varying(50),
    counterparty_entity_id uuid,
    effective_date date,
    expiration_date date,
    signed_date date,
    auto_renewal boolean DEFAULT false NOT NULL,
    renewal_period_months integer,
    renewal_notice_days integer,
    notice_period_days integer,
    termination_date date,
    termination_reason text,
    total_value numeric(15,2),
    currency character varying(3) DEFAULT 'EUR'::character varying NOT NULL,
    payment_terms jsonb DEFAULT '{}'::jsonb,
    clauses jsonb DEFAULT '{}'::jsonb,
    signatures jsonb DEFAULT '[]'::jsonb,
    risk_score integer,
    risk_factors jsonb DEFAULT '[]'::jsonb,
    extraction_confidence numeric(5,4),
    extraction_backend character varying(50),
    last_analyzed_at timestamp with time zone,
    analysis_version character varying(20),
    version_number integer DEFAULT 1 NOT NULL,
    parent_contract_id uuid,
    company_id uuid NOT NULL,
    created_by_id uuid,
    updated_by_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    tags jsonb DEFAULT '[]'::jsonb,
    notes text,
    CONSTRAINT ck_contracts_risk_score CHECK (((risk_score IS NULL) OR ((risk_score >= 0) AND (risk_score <= 100))))
);


