-- Name: cross_document_matches; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.cross_document_matches (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    company_id uuid NOT NULL,
    document_a_id uuid NOT NULL,
    document_b_id uuid NOT NULL,
    match_type character varying(50) NOT NULL,
    match_score double precision DEFAULT '0'::double precision NOT NULL,
    field_comparisons jsonb DEFAULT '[]'::jsonb,
    discrepancies jsonb DEFAULT '[]'::jsonb,
    status character varying(30) DEFAULT 'auto_matched'::character varying NOT NULL,
    reviewed_by uuid,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_cross_doc_match_score_range CHECK (((match_score >= (0.0)::double precision) AND (match_score <= (1.0)::double precision))),
    CONSTRAINT ck_cross_doc_match_status CHECK (((status)::text = ANY ((ARRAY['auto_matched'::character varying, 'confirmed'::character varying, 'rejected'::character varying, 'review_needed'::character varying])::text[]))),
    CONSTRAINT ck_cross_doc_match_type CHECK (((match_type)::text = ANY ((ARRAY['order_invoice'::character varying, 'delivery_invoice'::character varying, 'duplicate'::character varying, 'amendment'::character varying, 'order_delivery'::character varying])::text[])))
);


