    CONSTRAINT ck_datev_conn_kontenrahmen CHECK (((kontenrahmen)::text = ANY ((ARRAY['SKR03'::character varying, 'SKR04'::character varying])::text[]))),
    CONSTRAINT ck_datev_conn_personenkontenlange CHECK (((personenkontenlange >= 5) AND (personenkontenlange <= 9))),
    CONSTRAINT ck_datev_conn_sachkontenlange CHECK (((sachkontenlange >= 4) AND (sachkontenlange <= 8))),
