--
-- Name: extraction_confidences; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.extraction_confidences (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    document_id uuid NOT NULL,
    company_id uuid NOT NULL,
    field_name character varying(200) NOT NULL,
    extracted_value text NOT NULL,
    confidence_score double precision DEFAULT '0'::double precision NOT NULL,
    confidence_level character varying(20) DEFAULT 'low'::character varying NOT NULL,
    was_corrected boolean DEFAULT false,
    corrected_value text,
    corrected_by uuid,
    corrected_at timestamp with time zone,
    extraction_method character varying(50) NOT NULL,
    extraction_metadata jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_extraction_conf_level CHECK (((confidence_level)::text = ANY ((ARRAY['high'::character varying, 'medium'::character varying, 'low'::character varying])::text[]))),
    CONSTRAINT ck_extraction_conf_method CHECK (((extraction_method)::text = ANY ((ARRAY['ocr'::character varying, 'llm'::character varying, 'regex'::character varying, 'template'::character varying])::text[]))),
    CONSTRAINT ck_extraction_conf_score_range CHECK (((confidence_score >= (0.0)::double precision) AND (confidence_score <= (1.0)::double precision)))
);


