    resolution_notes text,
    detected_at timestamp with time zone DEFAULT now(),
    acknowledged_at timestamp with time zone,
    resolved_at timestamp with time zone,
    resolved_by_id uuid,
    CONSTRAINT ck_fraud_alert_severity CHECK (((severity)::text = ANY ((ARRAY['info'::character varying, 'low'::character varying, 'medium'::character varying, 'high'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT ck_fraud_alert_status CHECK (((status)::text = ANY ((ARRAY['open'::character varying, 'investigating'::character varying, 'confirmed'::character varying, 'false_positive'::character varying, 'resolved'::character varying])::text[])))
);


