    CONSTRAINT ck_fraud_scan_results_status CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'reviewed'::character varying, 'false_positive'::character varying, 'confirmed'::character varying, 'investigating'::character varying])::text[])))
);


