--
-- Name: gdpr_deletion_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.gdpr_deletion_status AS
 SELECT dr.id AS anfrage_id,
    dr.user_id,
    u.email AS benutzer_email,
    dr.status,
    dr.reason AS grund,
    dr.requested_at AS angefragt_am,
    dr.deletion_deadline AS frist,
    dr.completed_at AS abgeschlossen_am,
    dr.documents_deleted AS geloeschte_dokumente,
    dr.audit_entries_anonymized AS anonymisierte_audit_eintraege,
    dr.processed_by_id AS bearbeitet_von_id,
        CASE
            WHEN ((dr.status)::text = 'completed'::text) THEN 'Abgeschlossen'::text
            WHEN ((dr.status)::text = 'rejected'::text) THEN 'Abgelehnt'::text
            WHEN ((dr.status)::text = 'cancelled'::text) THEN 'Storniert'::text
            WHEN ((dr.status)::text = 'processing'::text) THEN 'In Bearbeitung'::text
            WHEN ((dr.deletion_deadline < now()) AND ((dr.status)::text = 'pending'::text)) THEN 'Ueberfaellig'::text
            WHEN ((dr.deletion_deadline < (now() + '7 days'::interval)) AND ((dr.status)::text = 'pending'::text)) THEN 'Frist bald'::text
            ELSE 'Offen'::text
        END AS status_anzeige,
        CASE
            WHEN ((dr.status)::text = 'pending'::text) THEN GREATEST((0)::numeric, (EXTRACT(epoch FROM (dr.deletion_deadline - now())) / (86400)::numeric))
            ELSE NULL::numeric
        END AS verbleibende_tage
   FROM (public.gdpr_deletion_requests dr
     LEFT JOIN public.users u ON ((u.id = dr.user_id)));


