    event_data jsonb DEFAULT '{}'::jsonb NOT NULL,
    document_id uuid,
    company_id uuid NOT NULL,
    user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    tsa_timestamp timestamp with time zone,
    tsa_token text,
    tsa_provider character varying(100),
    is_verified boolean NOT NULL,
    last_verified_at timestamp with time zone,
    verification_error text,
    CONSTRAINT ck_audit_chain_genesis CHECK ((((sequence_number = 1) AND (previous_hash IS NULL)) OR ((sequence_number > 1) AND (previous_hash IS NOT NULL))))
);


