--
-- Name: gobd_audit_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.gobd_audit_summary AS
 SELECT company_id,
    date_trunc('month'::text, created_at) AS monat,
    count(*) AS gesamt_eintraege,
    count(*) FILTER (WHERE (success = true)) AS erfolgreiche_aktionen,
    count(*) FILTER (WHERE (success = false)) AS fehlgeschlagene_aktionen,
    count(DISTINCT user_id) AS aktive_benutzer,
    count(*) FILTER (WHERE ((action)::text ~~ 'document%%'::text)) AS dokument_aktionen,
    count(*) FILTER (WHERE (((action)::text ~~ 'delete%%'::text) OR ((action)::text ~~ 'remove%%'::text))) AS loesch_aktionen,
    count(*) FILTER (WHERE ((action)::text ~~ 'export%%'::text)) AS export_aktionen,
    count(*) FILTER (WHERE ((action)::text ~~ 'login%%'::text)) AS login_aktionen,
    count(*) FILTER (WHERE (integrity_hash IS NOT NULL)) AS hash_verifizierte,
    min(created_at) AS erster_eintrag,
    max(created_at) AS letzter_eintrag
   FROM public.audit_logs al
  WHERE (company_id IS NOT NULL)
  GROUP BY company_id, (date_trunc('month'::text, created_at));


