    CONSTRAINT ck_gobd_check_type CHECK (((check_type)::text = ANY ((ARRAY['nachvollziehbarkeit'::character varying, 'nachpruefbarkeit'::character varying, 'unveraenderbarkeit'::character varying, 'vollstaendigkeit'::character varying, 'ordnung'::character varying, 'zeitgerechte_buchung'::character varying, 'aufbewahrung'::character varying, 'maschinelle_auswertbarkeit'::character varying, 'verfahrensdokumentation'::character varying, 'datensicherung'::character varying, 'zugangskontrolle'::character varying])::text[])))
