-- Name: integration_configs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.integration_configs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    company_id uuid NOT NULL,
    integration_type character varying(50) NOT NULL,
    display_name character varying(255) NOT NULL,
    config jsonb DEFAULT '{}'::jsonb NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    last_sync_at timestamp with time zone,
    last_sync_status character varying(20),
    last_error_message text,
    sync_interval_minutes integer DEFAULT 60 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT ck_integration_configs_interval_positive CHECK ((sync_interval_minutes > 0)),
    CONSTRAINT ck_integration_configs_last_status CHECK (((last_sync_status IS NULL) OR ((last_sync_status)::text = ANY ((ARRAY['success'::character varying, 'error'::character varying, 'partial'::character varying])::text[])))),
    CONSTRAINT ck_integration_configs_type CHECK (((integration_type)::text = ANY ((ARRAY['datev'::character varying, 'lexware'::character varying, 'banking'::character varying, 'slack'::character varying, 'email'::character varying])::text[])))
);


