--

CREATE TABLE public.integration_sync_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    integration_config_id uuid NOT NULL,
    company_id uuid NOT NULL,
    sync_type character varying(20) NOT NULL,
    status character varying(20) DEFAULT 'started'::character varying NOT NULL,
    items_processed integer DEFAULT 0 NOT NULL,
    items_failed integer DEFAULT 0 NOT NULL,
    items_total integer DEFAULT 0 NOT NULL,
    error_details jsonb DEFAULT '{}'::jsonb,
    started_at timestamp with time zone NOT NULL,
    completed_at timestamp with time zone,
    duration_seconds double precision,
    CONSTRAINT ck_sync_logs_items_non_negative CHECK (((items_processed >= 0) AND (items_failed >= 0) AND (items_total >= 0))),
    CONSTRAINT ck_sync_logs_status CHECK (((status)::text = ANY ((ARRAY['started'::character varying, 'success'::character varying, 'error'::character varying, 'partial'::character varying])::text[]))),
    CONSTRAINT ck_sync_logs_sync_type CHECK (((sync_type)::text = ANY ((ARRAY['full'::character varying, 'incremental'::character varying, 'manual'::character varying])::text[])))
);


