--

CREATE TABLE public.parallel_approvals (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    instance_id uuid NOT NULL,
    approval_key character varying(100) NOT NULL,
    element_id character varying(255) NOT NULL,
    title character varying(255) NOT NULL,
    description text,
    consensus_type character varying(30) NOT NULL,
    quorum_count integer,
    approvers jsonb NOT NULL,
    votes jsonb DEFAULT '{}'::jsonb NOT NULL,
    status character varying(30) NOT NULL,
    final_decision character varying(30),
    due_date timestamp with time zone,
    consensus_reached_at timestamp with time zone,
    cancelled_at timestamp with time zone,
    cancellation_reason text,
    created_by_id uuid,
    company_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_parallel_approvals_consensus_type CHECK (((consensus_type)::text = ANY ((ARRAY['all'::character varying, 'majority'::character varying, 'any'::character varying, 'unanimous'::character varying, 'quorum'::character varying])::text[]))),
    CONSTRAINT ck_parallel_approvals_status CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'approved'::character varying, 'rejected'::character varying, 'cancelled'::character varying, 'expired'::character varying])::text[])))
);


