    second_approved_at timestamp with time zone,
    executed_at timestamp with time zone,
    execution_result jsonb,
    execution_error text,
    expires_at timestamp with time zone NOT NULL,
    priority integer DEFAULT 50 NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_pending_action_category CHECK (((action_category)::text = ANY ((ARRAY['routine'::character varying, 'read_only'::character varying, 'modification'::character varying, 'notification'::character varying, 'financial'::character varying, 'deletion'::character varying, 'external'::character varying, 'legal'::character varying, 'compliance'::character varying])::text[]))),
    CONSTRAINT ck_pending_action_status CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'approved'::character varying, 'rejected'::character varying, 'expired'::character varying, 'auto_approved'::character varying, 'cancelled'::character varying])::text[]))),
    CONSTRAINT ck_pending_confidence_range CHECK (((confidence >= (0.0)::double precision) AND (confidence <= (1.0)::double precision))),
    CONSTRAINT ck_pending_priority_range CHECK (((priority >= 0) AND (priority <= 100)))
);


