    task_type character varying(50) NOT NULL,
    title character varying(255) NOT NULL,
    description text,
    category character varying(50),
    priority character varying(20) DEFAULT 'medium'::character varying NOT NULL,
    due_date timestamp with time zone,
    source_action_id uuid,
    source_reason text,
    source_module character varying(50),
    status character varying(30) DEFAULT 'pending'::character varying NOT NULL,
    started_at timestamp with time zone,
    completed_at timestamp with time zone,
    cancelled_at timestamp with time zone,
    cancelled_reason text,
    snoozed_until timestamp with time zone,
    snooze_count integer DEFAULT 0,
    snooze_reason character varying(255),
    result_notes text,
    result_action_taken character varying(100),
    related_entity_type character varying(50),
    related_entity_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    extra_data jsonb,
    CONSTRAINT chk_privat_task_priority CHECK (((priority)::text = ANY ((ARRAY['low'::character varying, 'medium'::character varying, 'high'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT chk_privat_task_status CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'in_progress'::character varying, 'completed'::character varying, 'cancelled'::character varying, 'snoozed'::character varying])::text[])))
);


