--
-- Name: search_analytics_daily; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.search_analytics_daily AS
 SELECT date_trunc('day'::text, created_at) AS date,
    search_type,
    count(*) AS total_searches,
    count(DISTINCT user_id) AS unique_users,
    (avg(total_results))::integer AS avg_results,
    (avg(execution_time_ms))::integer AS avg_execution_time_ms,
    (avg(clicked_results))::double precision AS avg_clicks_per_search,
    sum(
        CASE
            WHEN (total_results = 0) THEN 1
            ELSE 0
        END) AS zero_result_searches,
    sum(
        CASE
            WHEN has_document_type_filter THEN 1
            ELSE 0
        END) AS searches_with_type_filter,
    sum(
        CASE
            WHEN has_tag_filter THEN 1
            ELSE 0
        END) AS searches_with_tag_filter,
    sum(
        CASE
            WHEN has_date_filter THEN 1
            ELSE 0
        END) AS searches_with_date_filter
   FROM public.search_analytics
  GROUP BY (date_trunc('day'::text, created_at)), search_type
  ORDER BY (date_trunc('day'::text, created_at)) DESC, search_type
  WITH NO DATA;


