    company_id uuid NOT NULL,
    invoice_tracking_id uuid NOT NULL,
    entity_id uuid,
    recommendation character varying(50) NOT NULL,
    priority character varying(20) DEFAULT 'medium'::character varying NOT NULL,
    invoice_amount double precision NOT NULL,
    skonto_percentage double precision NOT NULL,
    skonto_amount double precision NOT NULL,
    skonto_deadline date NOT NULL,
    days_until_deadline integer NOT NULL,
    annualized_return double precision,
    opportunity_cost double precision,
    liquidity_impact double precision,
    cash_available double precision,
    liquidity_buffer_after double precision,
    reasoning text,
    factors jsonb,
    status character varying(30) DEFAULT 'new'::character varying NOT NULL,
    acted_upon boolean DEFAULT false NOT NULL,
    action_taken character varying(50),
    created_at timestamp with time zone DEFAULT now(),
    expires_at timestamp with time zone NOT NULL,
    acted_at timestamp with time zone,
    CONSTRAINT ck_skonto_rec_priority CHECK (((priority)::text = ANY ((ARRAY['high'::character varying, 'medium'::character varying, 'low'::character varying])::text[]))),
    CONSTRAINT ck_skonto_rec_status CHECK (((status)::text = ANY ((ARRAY['new'::character varying, 'acknowledged'::character varying, 'acted_upon'::character varying, 'dismissed'::character varying, 'expired'::character varying])::text[])))
);


