--
-- Name: user_effective_rate_limits; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.user_effective_rate_limits AS
 SELECT u.id AS user_id,
    u.email,
    u.tier,
    COALESCE(rlo.ocr_hourly, u.rate_limit_hourly,
        CASE u.tier
            WHEN 'admin'::text THEN 10000
            WHEN 'premium'::text THEN 100
            ELSE 10
        END) AS effective_ocr_hourly,
    COALESCE(rlo.ocr_daily, u.rate_limit_daily,
        CASE u.tier
            WHEN 'admin'::text THEN 100000
            WHEN 'premium'::text THEN 1000
            ELSE 50
        END) AS effective_ocr_daily,
    COALESCE(rlo.batch_hourly,
        CASE u.tier
            WHEN 'admin'::text THEN 1000
            WHEN 'premium'::text THEN 50
            ELSE 5
        END) AS effective_batch_hourly,
    COALESCE(rlo.api_per_minute,
        CASE u.tier
            WHEN 'admin'::text THEN 1000
            WHEN 'premium'::text THEN 100
            ELSE 20
        END) AS effective_api_per_minute,
    (rlo.id IS NOT NULL) AS has_override,
    rlo.valid_until AS override_valid_until,
    rlo.reason AS override_reason
   FROM (public.users u
     LEFT JOIN public.rate_limit_overrides rlo ON (((u.id = rlo.user_id) AND ((rlo.valid_until IS NULL) OR (rlo.valid_until > now())))));


