    steuerfrei_export double precision DEFAULT '0'::double precision NOT NULL,
    innergemeinschaftliche_lieferungen double precision DEFAULT '0'::double precision NOT NULL,
    vorsteuer_details jsonb,
    umsatzsteuer_details jsonb,
    status character varying(50) DEFAULT 'entwurf'::character varying NOT NULL,
    elster_xml text,
    notes text,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


--
-- Name: v_document_chains; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_document_chains AS
 SELECT chain_id,
    company_id,
    count(DISTINCT id) AS document_count,
    min(created_at) AS chain_started_at,
    max(created_at) AS chain_updated_at,
    array_agg(DISTINCT document_type) AS document_types,
    sum(
        CASE
            WHEN ((document_type)::text = 'invoice'::text) THEN 1
            ELSE 0
        END) AS invoice_count,
    sum(
        CASE
            WHEN ((document_type)::text = 'delivery_note'::text) THEN 1
            ELSE 0
        END) AS delivery_note_count,
    sum(
        CASE
            WHEN ((document_type)::text = 'order'::text) THEN 1
            ELSE 0
        END) AS order_count,
    ( SELECT count(*) AS count
           FROM public.document_chain_discrepancies dcd
          WHERE (((dcd.chain_id)::text = (d.chain_id)::text) AND (dcd.is_resolved = false))) AS open_discrepancies
   FROM public.documents d
  WHERE ((chain_id IS NOT NULL) AND (deleted_at IS NULL))
  GROUP BY chain_id, company_id;


--
-- Name: workflow_sla; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.workflow_sla (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    instance_id uuid NOT NULL,
    definition_id uuid NOT NULL,
    max_duration_hours integer NOT NULL,
    start_time timestamp with time zone NOT NULL,
    deadline timestamp with time zone NOT NULL,
    status character varying(30) NOT NULL,
    current_alert_level character varying(30),
    alerts_sent jsonb DEFAULT '[]'::jsonb NOT NULL,
    completed_at timestamp with time zone,
    was_on_time boolean,
    actual_duration_hours double precision,
    breach_by_hours double precision,
    escalated boolean NOT NULL,
    escalated_at timestamp with time zone,
    escalation_user_id uuid,
    company_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_workflow_sla_status CHECK (((status)::text = ANY ((ARRAY['on_track'::character varying, 'warning'::character varying, 'at_risk'::character varying, 'critical'::character varying, 'breached'::character varying])::text[])))
);


--
-- Name: COLUMN workflow_sla.status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workflow_sla.status IS 'on_track, warning, at_risk, critical, breached';


--
-- Name: COLUMN workflow_sla.current_alert_level; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workflow_sla.current_alert_level IS 'info_50, warning_75, high_90, critical_100';


--
-- Name: COLUMN workflow_sla.alerts_sent; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workflow_sla.alerts_sent IS 'Liste der gesendeten Alert-Typen';


--
-- Name: v_workflow_sla_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_workflow_sla_summary AS
 SELECT ws.company_id,
    pd.key AS workflow_key,
    pd.name AS workflow_name,
    count(*) AS total_instances,
    count(*) FILTER (WHERE (ws.was_on_time = true)) AS on_time_count,
    count(*) FILTER (WHERE (ws.was_on_time = false)) AS breached_count,
    count(*) FILTER (WHERE (ws.completed_at IS NULL)) AS active_count,
    round((((count(*) FILTER (WHERE (ws.was_on_time = true)))::numeric / (NULLIF(count(*) FILTER (WHERE (ws.completed_at IS NOT NULL)), 0))::numeric) * (100)::numeric), 2) AS compliance_rate,
    round((avg(ws.actual_duration_hours))::numeric, 2) AS avg_duration_hours,
    round((avg(ws.breach_by_hours) FILTER (WHERE (ws.was_on_time = false)))::numeric, 2) AS avg_breach_hours
   FROM ((public.workflow_sla ws
     JOIN public.bpmn_process_instances pi ON ((ws.instance_id = pi.id)))
     JOIN public.bpmn_process_definitions pd ON ((pi.definition_id = pd.id)))
  GROUP BY ws.company_id, pd.key, pd.name;


